{"filter":false,"title":"mqtt_client.py","tooltip":"/mqtt_client.py","undoManager":{"mark":2,"position":2,"stack":[[{"start":{"row":0,"column":0},"end":{"row":202,"column":40},"action":"insert","lines":["import json","import threading","import time","from datetime import datetime","import paho.mqtt.client as mqtt","import boto3","from decimal import Decimal","","class MQTTDataClient:","    def __init__(self, broker_host, broker_port=1883, topics=None):","        self.broker_host = broker_host","        self.broker_port = broker_port","        self.topics = topics or [\"waste/processing/sensor/data\"]","        self.client = None","        self.received_data = []","        self.max_data_points = 500","        self.is_connected = False","        self.latest_data = {}","        ","        # For Lambda fallback","        self.use_lambda_fallback = True","        self.lambda_api_url = \"https://your-lambda-2-api-gateway-url.amazonaws.com/default/store-data\"","        self.dynamodb_table = None","        ","        # Initialize DynamoDB backup","        try:","            dynamodb = boto3.resource('dynamodb', region_name='us-east-1')","            self.dynamodb_table = dynamodb.Table('x23389401-waste-processing-data')","        except Exception as e:","            print(f\"DynamoDB initialization failed: {e}\")","    ","    def on_connect(self, client, userdata, flags, rc):","        if rc == 0:","            self.is_connected = True","            print(f\"Connected to MQTT broker at {self.broker_host}:{self.broker_port}\")","            # Subscribe to topics","            for topic in self.topics:","                client.subscribe(topic)","                print(f\"Subscribed to: {topic}\")","        else:","            print(f\"Failed to connect to MQTT broker with code: {rc}\")","            self.is_connected = False","    ","    def on_message(self, client, userdata, msg):","        try:","            payload = msg.payload.decode('utf-8')","            data = json.loads(payload)","            ","            # Add received timestamp","            data['received_timestamp'] = datetime.utcnow().isoformat()","            ","            # Store in memory","            self.received_data.append(data)","            if len(self.received_data) > self.max_data_points:","                self.received_data = self.received_data[-self.max_data_points:]","            ","            # Update latest data","            self.latest_data = data","            ","            # Store in DynamoDB as backup","            self.store_in_dynamodb(data)","            ","            print(f\"Received data from {data.get('device_id', 'Unknown')}\")","            ","        except json.JSONDecodeError as e:","            print(f\"Invalid JSON received: {e}\")","        except Exception as e:","            print(f\"Error processing message: {e}\")","    ","    def on_disconnect(self, client, userdata, rc):","        self.is_connected = False","        print(\"Disconnected from MQTT broker\")","    ","    def store_in_dynamodb(self, data):","        \"\"\"Store data in DynamoDB as backup\"\"\"","        if not self.dynamodb_table:","            return","        ","        try:","            timestamp_str = data.get(\"timestamp\", datetime.utcnow().isoformat())","            timestamp_dt = datetime.fromisoformat(timestamp_str.replace('Z', '+00:00'))","            partition_key = f\"{data.get('device_id', 'unknown')}_{timestamp_dt.strftime('%Y-%m-%d')}\"","            ","            item = {","                \"device_date\": partition_key,","                \"timestamp\": timestamp_str,","                \"device_id\": data.get(\"device_id\"),","                \"sensor_id\": data.get(\"sensor_id\"),","                \"ph\": Decimal(str(data.get(\"ph\", 0))),","                \"air_quality\": int(data.get(\"air_quality\", 0)),","                \"temperature\": Decimal(str(data.get(\"temperature\", 0))),","                \"weight\": Decimal(str(data.get(\"weight\", 0))),","                \"pressure\": Decimal(str(data.get(\"pressure\", 0))),","                \"gas\": int(data.get(\"gas\", 0)),","                \"status\": data.get(\"status\", \"UNKNOWN\"),","                \"critical_alerts\": data.get(\"critical_alerts\", []),","                \"warning_alerts\": data.get(\"warning_alerts\", []),","                \"processed_timestamp\": datetime.utcnow().isoformat()","            }","            ","            self.dynamodb_table.put_item(Item=item)","        except Exception as e:","            print(f\"Failed to store in DynamoDB: {e}\")","    ","    def connect(self):","        \"\"\"Connect to MQTT broker\"\"\"","        self.client = mqtt.Client()","        self.client.on_connect = self.on_connect","        self.client.on_message = self.on_message","        self.client.on_disconnect = self.on_disconnect","        ","        try:","            self.client.connect(self.broker_host, self.broker_port, 60)","            self.client.loop_start()","            return True","        except Exception as e:","            print(f\"Failed to connect to MQTT broker: {e}\")","            return False","    ","    def disconnect(self):","        \"\"\"Disconnect from MQTT broker\"\"\"","        if self.client:","            self.client.loop_stop()","            self.client.disconnect()","            self.is_connected = False","    ","    def get_latest_data(self):","        \"\"\"Get the latest sensor reading\"\"\"","        return self.latest_data","    ","    def get_recent_data(self, count=50):","        \"\"\"Get recent sensor readings\"\"\"","        return self.received_data[-count:] if self.received_data else []","    ","    def get_status(self):","        \"\"\"Get connection status\"\"\"","        return {","            \"connected\": self.is_connected,","            \"data_points\": len(self.received_data),","            \"latest_timestamp\": self.latest_data.get(\"timestamp\") if self.latest_data else None,","            \"broker\": self.broker_host,","            \"topics\": self.topics","        }","","def fetch_from_dynamodb(device_id=None, start_date=None, end_date=None, limit=100):","    \"\"\"Direct fetch from DynamoDB as backup\"\"\"","    try:","        dynamodb = boto3.resource('dynamodb', region_name='us-east-1')","        table = dynamodb.Table('x23389401-waste-processing-data')","        ","        if device_id:","            response = table.query(","                KeyConditionExpression=\"device_date = :device_date\",","                ExpressionAttributeValues={\":device_date\": device_id},","                Limit=limit,","                ScanIndexForward=False","            )","        else:","            response = table.scan(Limit=limit)","        ","        items = response.get(\"Items\", [])","        ","        # Convert Decimal to float","        def decimal_to_float(obj):","            if isinstance(obj, list):","                return [decimal_to_float(i) for i in obj]","            elif isinstance(obj, dict):","                return {k: decimal_to_float(v) for k, v in obj.items()}","            elif isinstance(obj, Decimal):","                return float(obj)","            else:","                return obj","        ","        return decimal_to_float(items)","        ","    except Exception as e:","        print(f\"Error fetching from DynamoDB: {e}\")","        return []","","def run_mqtt_client(broker_host=\"test.mosquitto.org\", broker_port=1883):","    \"\"\"Run the MQTT client\"\"\"","    client = MQTTDataClient(broker_host, broker_port)","    if client.connect():","        print(\"MQTT client started successfully\")","        print(f\"Listening to topics: {client.topics}\")","        return client","    else:","        print(\"Failed to start MQTT client\")","        return None","","if __name__ == \"__main__\":","    # Test the client","    client = run_mqtt_client()","    ","    if client:","        try:","            while True:","                time.sleep(5)","                status = client.get_status()","                print(f\"Status: {status}\")","        except KeyboardInterrupt:","            client.disconnect()","            print(\"MQTT client stopped\")"],"id":1}],[{"start":{"row":12,"column":34},"end":{"row":12,"column":62},"action":"remove","lines":["waste/processing/sensor/data"],"id":2},{"start":{"row":12,"column":34},"end":{"row":12,"column":56},"action":"insert","lines":["waste/processing/plant"]}],[{"start":{"row":27,"column":50},"end":{"row":27,"column":81},"action":"remove","lines":["x23389401-waste-processing-data"],"id":3},{"start":{"row":27,"column":50},"end":{"row":27,"column":74},"action":"insert","lines":["x25105990-dynamodb-table"]},{"start":{"row":148,"column":32},"end":{"row":148,"column":63},"action":"remove","lines":["x23389401-waste-processing-data"]},{"start":{"row":148,"column":32},"end":{"row":148,"column":56},"action":"insert","lines":["x25105990-dynamodb-table"]}]]},"ace":{"folds":[],"scrolltop":2017,"scrollleft":0,"selection":{"start":{"row":82,"column":12},"end":{"row":82,"column":12},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":{"row":225,"mode":"ace/mode/python"}},"timestamp":1783594508473,"hash":"de4000ebb2cc9078dfa206af8defb9fe7bed6d0d"}